import { Button } from '@/components/ui/button';
import { Form, Input } from '@/components/ui/form';
import { paths } from '@/config/paths';
import { useLogin, loginInputSchema } from '@/lib/auth';

type LoginFormProps = {
  onSuccess: () => void;
};

export const LoginForm = ({ onSuccess }: LoginFormProps) => {
  const login = useLogin({
    onSuccess,
  });
  const [searchParams] = useSearchParams();
  const redirectTo = searchParams.get('redirectTo');

  return (
    <div>
      <Form
        onSubmit={(values) => {
          login.mutate(values);
        }}
        schema={loginInputSchema}
      >
        {({ register, formState }) => (
          <>
            <Input
              type="email"
              label="Email Address"
              error={formState.errors['email']}
              registration={register('email')}
            />
            <Input
              type="password"
              label="Password"
              error={formState.errors['password']}
              registration={register('password')}
            />
            <div>
              <Button
                isLoading={login.isPending}
                type="submit"
                className="w-full"
              >
                Log in
              </Button>
            </div>
          </>
        )}
      </Form>
      <div className="mt-2 flex items-center justify-end">
        <div className="text-sm">
          <Link
            to={paths.auth.register.getHref(redirectTo)}
            className="font-medium text-blue-600 hover:text-blue-500"
          >
            Register
          </Link>
        </div>
      </div>
    </div>
  );
};
"}]}

The `Button` component accepts the following props:

1.  `className`
2.  `variant`
3.  `size`
4.  `asChild` (defaults to `false`)
5.  `children`
6.  `isLoading`
7.  `icon`
8.  `ref`
9.  Any other standard HTML button attributes (via spread `props`)

In the `LoginForm` component (found in `src/features/auth/components/login-form.tsx`), the `isLoading` prop for the `Button` originates from the `isPending` state of the `useLogin` hook:

```tsx
export const LoginForm = ({ onSuccess }: LoginFormProps) => {
  const login = useLogin({
    onSuccess,
  });

  // ...

  return (
    // ...
    <Button
      isLoading={login.isPending} // Data originates here from the useLogin hook
      type="submit"
      className="w-full"
    >
      Log in
    </Button>
    // ...
  );
};
```

